        12 ) dyd_ret0=c ;; 13 ) dyd_ret0=d ;; 14 ) dyd_ret0=e ;; 15 ) dyd_ret0=f ;;
        * ) dryad_die "invalid hex nibble: $1" ;;
    esac
}

