    dyd_b2_32_base32_char_shell_append $((((dyd_b2_32_d12 & 15) << 1) | (dyd_b2_32_d13 >> 7)))
    dyd_b2_32_base32_char_shell_append $(((dyd_b2_32_d13 >> 2) & 31))
    dyd_b2_32_base32_char_shell_append $((((dyd_b2_32_d13 & 3) << 3) | (dyd_b2_32_d14 >> 5)))
    dyd_b2_32_base32_char_shell_append $((dyd_b2_32_d14 & 31))
    dyd_b2_32_base32_char_shell_append $((dyd_b2_32_d15 >> 3))
    dyd_b2_32_base32_char_shell_append $(((dyd_b2_32_d15 & 7) << 2))
    dyd_ret0=$dyd_b2_32_base32_output
}

dyd_b2_32_hash_file_shell () {
    dyd_b2_32_file=$1
    dyd_b2_32_format=${2:-hex}
    dyd_b2_32_od_tmp=${TMPDIR:-/tmp}/dryad-sh-hash-32-od.$$
    rm -f "$dyd_b2_32_od_tmp"
    if ! od -An -v -tu1 -w128 "$dyd_b2_32_file" > "$dyd_b2_32_od_tmp"; then
        rm -f "$dyd_b2_32_od_tmp"
        return 1
    fi
    dyd_b2_32_reset_shell
    dyd_b2_32_have_block=0
    dyd_b2_32_pending_line=
    while IFS= read -r dyd_b2_32_line; do
        [ -n "$dyd_b2_32_line" ] || continue
        if [ "$dyd_b2_32_have_block" = 1 ]; then
            set -- $dyd_b2_32_pending_line
            dyd_b2_32_load_block_shell "$@"
            dyd_b2_32_add_counter_shell "$dyd_b2_32_block_len"
            dyd_b2_32_compress_shell 0
        fi
        dyd_b2_32_pending_line=$dyd_b2_32_line
        dyd_b2_32_have_block=1
    done < "$dyd_b2_32_od_tmp"
    rm -f "$dyd_b2_32_od_tmp"
    if [ "$dyd_b2_32_have_block" = 1 ]; then
        set -- $dyd_b2_32_pending_line
        dyd_b2_32_load_block_shell "$@"
    else
        dyd_b2_32_load_block_shell
    fi
    dyd_b2_32_add_counter_shell "$dyd_b2_32_block_len"
    dyd_b2_32_compress_shell 1
    case $dyd_b2_32_format in
        base32 ) dyd_b2_32_output_base32_shell_load ;;
        hex ) dyd_b2_32_output_hex_shell_load ;;
        * ) dryad_die "unsupported 32-bit shell hash format: $dyd_b2_32_format" ;;
    esac
}

dryad_blake2b_128_file_hex_shell_32_load () {
    dyd_b2_32_hash_file_shell "$1" hex
}

dryad_blake2b_128_file_base32_shell_32_load () {
    dyd_b2_32_hash_file_shell "$1" base32
}

dryad_blake2b_128_file_prefixed_base32_shell_32_load () {
    dyd_b2_32_prefixed_file=$1
    dyd_b2_32_od_tmp=${TMPDIR:-/tmp}/dryad-sh-hash-32-od.$$
    rm -f "$dyd_b2_32_od_tmp"
    if ! od -An -v -tu1 -w128 "$dyd_b2_32_prefixed_file" > "$dyd_b2_32_od_tmp"; then
        rm -f "$dyd_b2_32_od_tmp"
        return 1
    fi
    dyd_b2_32_reset_shell
    dyd_b2_32_have_block=0
    dyd_b2_32_loaded_block=0
    dyd_b2_32_pending_line=
    while IFS= read -r dyd_b2_32_line; do
        [ -n "$dyd_b2_32_line" ] || continue
        if [ "$dyd_b2_32_have_block" = 1 ]; then
            set -- $dyd_b2_32_pending_line
            if [ "$dyd_b2_32_loaded_block" = 0 ]; then
                dyd_b2_32_load_initial_prefixed_block_shell "$@"
            else
                dyd_b2_32_load_carried_prefixed_block_shell "$@"
            fi
            dyd_b2_32_add_counter_shell "$dyd_b2_32_block_len"
            dyd_b2_32_compress_shell 0
            dyd_b2_32_loaded_block=1
        fi
        dyd_b2_32_pending_line=$dyd_b2_32_line
        dyd_b2_32_have_block=1
    done < "$dyd_b2_32_od_tmp"
    rm -f "$dyd_b2_32_od_tmp"
    if [ "$dyd_b2_32_have_block" = 1 ]; then
        set -- $dyd_b2_32_pending_line
        if [ "$dyd_b2_32_loaded_block" = 0 ]; then
            dyd_b2_32_load_initial_prefixed_block_shell "$@"
        else
            dyd_b2_32_load_carried_prefixed_block_shell "$@"
        fi
    else
        dyd_b2_32_load_initial_prefixed_block_shell
    fi
    if [ "$dyd_b2_32_carry_len" -gt 0 ]; then
        dyd_b2_32_add_counter_shell "$dyd_b2_32_block_len"
        dyd_b2_32_compress_shell 0
        dyd_b2_32_load_final_carry_block_shell
    fi
    dyd_b2_32_add_counter_shell "$dyd_b2_32_block_len"
    dyd_b2_32_compress_shell 1
    dyd_b2_32_output_base32_shell_load
}
